var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"커어어……","JPN":"ゴオオ……","ENG":"Groarghhhrr...","TWN":"呼嚕嚕……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_06"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"크어어어……","JPN":"グウウウ……","ENG":"Grrroar!!!","TWN":"呼嚕嚕嚕……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_02"},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이 소리는… 침식체인가?","JPN":"この音は……侵食体なのか？","ENG":"What's that sound...? Another C.O.?","TWN":"這個聲音是… 侵蝕體嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"곤란하군. 하필이면 무기가 없을 때에……","JPN":"まいったな。よりによって武器を持っていない時に……","ENG":"This isn't good. I don't have my weapon with me...","TWN":"真傷腦筋，偏偏挑我沒武器的時候……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"커어어어…….","JPN":"ゴオオオ……","ENG":"Groarghhhrr...","TWN":"呼嚕嚕……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"크어어어어…….","JPN":"グウウウウ……","ENG":"Grrroar!!!","TWN":"呼嚕嚕嚕……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장교님…?","JPN":"将校……？","ENG":"Officer...?","TWN":"軍官…？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"음…? 흐으음…….","JPN":"うん……？　ふうーん……","ENG":"Mm...? Hmm...","TWN":"嗯…？呃嗯嗯……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"깨우지 마. 방금 잠들었으니까.","JPN":"起こさないで。今眠ったばかりだから。","ENG":"Don't wake her up. She just fell asleep.","TWN":"別吵醒她，她才剛睡著而已。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…대장? 내가 또 의식을 잃었던 건가?","JPN":"……隊長？　私はまた気を失ったのか？","ENG":"Captain? Did I lose consciousness again?","TWN":"…隊長？我又暈過去了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래. 쓰러진 널 저 장교님이 혼자서 업고 마을까지 데려왔어.","JPN":"そう。倒れたあなたをあの将校が一人でおぶって村まで連れて来たよ。","ENG":"Correct. She carried you on her back and brought you to the village all by herself.","TWN":"沒錯，是她自己把你揹回村裡的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저 작은 체격으로? 농담이 과하군.","JPN":"あの小さな体で？　冗談もほどほどにしてくれ。","ENG":"She carried me on her tiny back? Now that's a cruel joke.","TWN":"她身材那麼嬌小？你在跟我開玩笑嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"농담이 아니야. 마을에 도착했을 때는 기진맥진해서 거의 질질 끌다시피 했지만.","JPN":"冗談じゃない。村に着いた頃にはへとへとになって、ほとんど引きずっているような状態だったけど。","ENG":"I'm not joking. She was practically dragging you from exhaustion by the time she arrived.","TWN":"不是開玩笑，她到村裡時候已經筋疲力盡，幾乎是用拖的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런데 당신은 허밋이 없으면 제대로 뛰어다니지도 못하는 주제에 어디까지 갔던 거야?","JPN":"ところで、ハーミットなしではまともに走れもしない人が、どこまで行ってたの？","ENG":"Where did you two even go? You know you can't go far without Hermit.","TWN":"倒是你，沒有赫米特就不能隨便移動，剛是跑哪裡去？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"미안하다. 장교님과 함께 다녀올 곳이 있었어.","JPN":"すまない。将校と一緒に行く場所があったんだ。","ENG":"Sorry about that. But there was a place I needed to take her.","TWN":"對不起，我和軍官一起去一個地方。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"몸 상태는? 팔다리는 움직일 수 있겠어?","JPN":"体の具合は？　手足は動かせる？","ENG":"How are you feeling? Can you move your arms and legs?","TWN":"身體狀況如何？手臂和腿能動嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"좀 뻣뻣하긴 하지만, 어떻게든.","JPN":"少々強張ってはいるが、なんとか。","ENG":"They're a little stiff, but nothing serious.","TWN":"是有點僵硬。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"환각 증세는? 갑자기 살인 충동을 느끼거나 자기도 모르게 그르렁거린 적 있어?","JPN":"幻覚症状は？　いきなり殺人の衝動を覚えるとか、我知らず唸り声を上げたことは？","ENG":"What about hallucinations? Do you feel like growling or suddenly have the urge to kill someone?","TWN":"幻覺的部分呢？有沒有突然覺得有殺人衝動，或者不自覺吼叫？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런 걸 물어볼 만큼 심각한 상태인 건가?","JPN":"そういうことを聞くほど深刻な状態なのか？","ENG":"Is my condition so bad that you have to ask those questions?","TWN":"我有嚴重到需要問這些問題嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"물론 침식 증후군의 진행 속도는 환자마다 달라.","JPN":"もちろん侵食症候群の進行速度は人それぞれ違うよ。","ENG":"The rate at which Corruption Syndrome progresses varies from patient to patient.","TWN":"侵蝕症候群的發作速度會因病患而有所不同。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 당신은 1년 전부터 말기였어. 언제 침식체로 돌변해도 이상하지 않은 기간이지.","JPN":"でもあなたは1年前から末期だった。いつ急に侵食体になってもおかしくない期間なのよ。","ENG":"However, you were already in the later stages a year ago. So it wouldn't be surprising to see you turn into a C.O. at any time now.","TWN":"但一年前你便已經進入末期，什麼時候變成侵蝕體都不意外。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"실제로 최근 들어 의식을 잃고 쓰러지는 빈도도 꾸준히 늘고 있으니까.","JPN":"実際、最近気を失って倒れる頻度も増え続けてるから。","ENG":"What's more is that the frequency of your fainting has been increasing at a consistent rate.","TWN":"而且，你最近暈倒的頻率也越來越高。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"단순한 빈혈일 가능성도 있지 않나?","JPN":"単なる貧血という可能性もあるんじゃないか？","ENG":"What if it's just anemia?","TWN":"也有可能單純是貧血吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"현실 부정은 적당히 해 둬.","JPN":"現実を否定するのもほどほどにして。","ENG":"There's no point in denying it.","TWN":"不要逃避現實。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"눈으로만 봐도 그 몸에는 침식의 흔적이 또렷해. 안락사 권유할 단계는 예전에 지났어.","JPN":"あなたの体には侵食の跡がはっきり見てとれる。安楽死をおすすめする段階はとっくに過ぎてるよ。","ENG":"Anyone can see the traces of Corruption clear as day all over your body. Plus, it has already advanced past recommending euthanasia.","TWN":"光用肉眼看，都看得出來你身上有明顯的侵蝕痕跡，現在你已經沒機會選擇安樂死的餘地。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"앞으로는 병실에서 얌전히 지내도록 해. 대원들 앞에서 침식체가 되고 싶은 건 아니잖아?","JPN":"これからは病室で大人しくすること。隊員の前で侵食体になりたくはないでしょ？","ENG":"I want you to stay in your room from now on. You don't want to turn into a C.O. in front of everyone, do you?","TWN":"以後你就乖乖待在病房，你應該不想在隊員面前變成侵蝕體吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"열쇠를 되찾을 기회가 눈앞에 있어. 나에겐 시간이 조금이라도 더 필요해.","JPN":"鍵を取り戻す機会が目の前にあるんだ。少しでも時間がほしい。","ENG":"But my chance to recover the Key is right in front of me. I just need a little more time.","TWN":"好不容易有找到鑰匙的機會，我需要再多一點時間。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고집 부리는 꼴이 보기 좋지 않다는 건 알고 있지만…… 미안하다.","JPN":"意地を張るのは見苦しいとわかってはいるが……すまない。","ENG":"I know I'm being stubborn... and I'm sorry.","TWN":"我知道這樣一直吵很不好看……對不起。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하아…. 어련하시겠어.","JPN":"はあ……確かにそうだね。","ENG":"*Sigh...* I knew you'd say something like that.","TWN":"哀… 你說的沒錯。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…이건?","JPN":"……これは？","ENG":"What's this?","TWN":"…這是？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"억제 주사야. 위기라고 생각되면 정맥에 대고 버튼을 눌러.","JPN":"抑制注射。危ないと思ったら静脈に当ててボタンを押して。","ENG":"It's an inhibitor. Press it against your vein and push the button whenever you feel like your life is in danger.","TWN":"是抑制注射，覺得有危險時，就對著靜脈按鈕。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"원리는 이터니움 정제액과 비슷하지만… 말기 환자에게도 먹힐 만큼 효과는 확실해.","JPN":"原理はエタニウム精製水と似てるんだけど……末期患者にも確実に効果はある。","ENG":"It works similar to that of purified Eternium liquid... But it's highly effective on late-stage patients as well.","TWN":"雖然原理類似永恆之金的淨化液…但對末期病患使用效果確實也很好。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고맙군, 대장.","JPN":"ありがとう、隊長。","ENG":"Thank you, Captain.","TWN":"隊長，謝謝你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"고마워하지 마. 넌 지금 의사한테 절대 해선 안 될 부탁을 한 거니까.","JPN":"礼はしなくていいよ。あなたは今医者に絶対にしてはいけないことを頼んだわけだから。","ENG":"Don't thank me. You just asked a doctor for something that no one should ever do.","TWN":"不用謝，你現在是在拜託醫生做不該做的事。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"투약 즉시 사망할 수 있을 정도로 강력한 억제제야. 섣불리 사용했다간 뒷일은 장담 못 해.","JPN":"投薬と同時に死亡する可能性もあるくらい強力な抑制剤よ。下手に使えば後にどうなるか保障できない。","ENG":"I can't guarantee that you'll survive after injecting that into your system. That's how potent it is.","TWN":"這是一種強效的抑制劑，用藥後可能會立刻死亡，千萬要小心使用，否則後果不堪設想。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"알겠다. 되도록이면 임무를 마칠 때 그대로 돌려 주도록 하지.","JPN":"わかった。なるべく任務が終わったらそのまま返そう。","ENG":"Understood. I'll try to give it back to you in one piece after the mission.","TWN":"好的，我會儘量在完成任務時，原封不動地還給你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"으음…?","JPN":"うむ……？","ENG":"Hmm...?","TWN":"嗯嗯…？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……내가 얼마나 잠들었지?","JPN":"……私はどのくらい寝てたんだ？","ENG":"How long was I out?","TWN":"……我睡了多久？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"삼십 분 정도 지났습니다.","JPN":"30分くらい過ぎました。","ENG":"About thirty minutes.","TWN":"30分鐘左右。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"망할… 아까운 시간을 허비해 버렸군.","JPN":"くそ……大事な時間を無駄にしてしまったな。","ENG":"Crud... I wasted valuable time.","TWN":"該死…浪費這麼多寶貴的時間。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"당장 탐지기를 수리해야겠어.","JPN":"今すぐ探知機を修理しないと。","ENG":"I should get back to repairing the detector.","TWN":"我必須馬上修好探測器。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"감사합니다, 장교님. 절 여기까지 옮겨 주셨다고 하더군요.","JPN":"ありがとうございます、将校。私をここまで運んでくださったと聞きました。","ENG":"Thank you, officer. I heard you carried me all the way back.","TWN":"謝謝你，軍官，聽說是你把我揹回這裡的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥. 그런 상태인 줄 알았으면 애초에 따라오게 허락하지도 않았을 거다.","JPN":"フン。そんな状態だと知っていたなら、最初から付いてくることを許可しなかったはずだ。","ENG":"Hmph. If I had known about your condition I wouldn't have allowed you to follow me in the first place.","TWN":"哼，早知道你會這樣，當初才不會允許你跟來。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"제 몸 하나 못 가누는 중환자에게 지휘권을 주다니, 수비대장의 안목도 정말이지……","JPN":"自分の体も支えられない重症患者に指揮権を与えるなんて、守備隊長の目はまったく……","ENG":"Giving a man like that the position of Commanding Officer... I don't know what you were thinking, Cap─","TWN":"竟然將指揮權交給這種身體虛弱的重症病患，護衛隊長的眼光也真是……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그러고 보니 곧 저녁 식사 시간이군요.","JPN":"そういえばもうすぐ夕飯の時間ですね。","ENG":"Dinner should be ready soon.","TWN":"差不多該吃晚餐了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"잠시만 기다려 주시면 방으로 음식을 가져가겠습니다, 장교님.","JPN":"しばらくお待ちいただければ部屋に夕食をお持ちします、将校。","ENG":"If you wait a little longer, I'll bring it up to your room, Officer Rashford.","TWN":"請稍等一下，我會把晚餐送到房間給你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……아니. 번거롭게 그럴 필요 없어.","JPN":"……いや。その必要はない。","ENG":"No. There's no need for that.","TWN":"……不，不需要這麼麻煩。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"오늘 석식은 식당에서 하겠다. 한나 씨에게도 전해 주도록.","JPN":"今日の夕食は食堂で済ませる。ハンナさんにも伝えてくれ。","ENG":"I'll eat in the cafeteria tonight. Tell Hanna I'll be there.","TWN":"我今天要在飯廳吃晚餐，幫我轉告漢娜。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};